async function updateAvailability(title, newStatus) {
  try {
    const updatedBook = await Book.findOneAndUpdate(
      { title: title },
      { available: newStatus },
      { new: true } // retourne le document après mise à jour
    );
    if (!updatedBook) throw new Error('Livre introuvable');
    return updatedBook;
  } catch (error) {
    console.error(error);
    return null;
  }
}
```

