```javascript
const orderSchema = new mongoose.Schema({
  orderId: { type: String, required: true, unique: true },
  customer: { type: String, required: true },
  total: { type: Number, default: 0 },
  status: {
    type: String,
    enum: ['pending', 'paid', 'shipped', 'delivered'],
    default: 'pending'
  },
  items: [{
    title: String,
    quantity: Number,
    price: Number
  }]
});

// méthode d'instance pour recalculer le total
orderSchema.methods.recalculateTotal = function() {
  const sum = this.items.reduce((acc, item) => acc + (item.quantity * item.price), 0);
  this.total = sum;
  return this.save();
};

const Order = mongoose.model('Order', orderSchema);
```

```javascript
async function updateOrderTotal(orderId) {
  const order = await Order.findOne({ orderId });
  if (!order) throw new Error('Commande introuvable');
  await order.recalculateTotal();
  return order.total;
}
```

